package com.archiveos.ai.memory; import java.util.*; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/memory") public class MemoryController {private final MemoryService s;public MemoryController(MemoryService s){this.s=s;}@PostMapping("/drafts")public Map<String,Object> draft(@RequestBody Map<String,Object>b){return Map.of("data",s.draft(String.valueOf(b.get("sourceRecommendationId"))));}@GetMapping("/drafts/{id}")public ResponseEntity<Map<String,Object>> get(@PathVariable String id){Map<String,Object>v=s.get(id);return v==null?ResponseEntity.notFound().build():ResponseEntity.ok(Map.of("data",v));}@PostMapping("/drafts/{id}/approve")public ResponseEntity<Map<String,Object>> approve(@PathVariable String id,@RequestBody(required=false)Map<String,Object>b,Authentication a){Map<String,Object>v=s.approve(id,a.getName(),b==null?null:String.valueOf(b.get("reason")));return v==null?ResponseEntity.notFound().build():ResponseEntity.ok(Map.of("data",v));}@PostMapping("/drafts/{id}/write")public ResponseEntity<Map<String,Object>> write(@PathVariable String id){Map<String,Object>v=s.write(id);return v==null?ResponseEntity.notFound().build():ResponseEntity.ok(Map.of("data",v));}@GetMapping("/records")public Map<String,Object>list(){return Map.of("data",s.list());}@GetMapping("/records/{id}")public ResponseEntity<Map<String,Object>>record(@PathVariable String id){return get(id);}}
